import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { ArrowLeft, User, LogOut } from "lucide-react";
import { useAuth } from "./AuthContext";

export default function Profile() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      <div className="flex justify-between items-center mb-8">
        <button
          onClick={() => navigate("/dashboard")}
          className="flex items-center gap-2 text-blue-600 hover:text-blue-800"
        >
          <ArrowLeft className="w-5 h-5" /> Back
        </button>
        <button
          onClick={handleLogout}
          className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700"
        >
          <LogOut className="w-5 h-5" /> Logout
        </button>
      </div>

      <div className="max-w-2xl mx-auto bg-white rounded-lg shadow p-8">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center">
            <User className="w-8 h-8 text-blue-600" />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-900">
              {user?.name || "Jane Doe"}
            </h1>
            <p className="text-gray-600">
              {user?.email || "jane.doe@university.edu"}
            </p>
          </div>
        </div>

        <div className="space-y-6 mb-8">
          <div>
            <h3 className="text-sm font-semibold text-gray-700">
              Graduation Year
            </h3>
            <p className="text-lg text-gray-900">2020</p>
          </div>
          <div>
            <h3 className="text-sm font-semibold text-gray-700">Company</h3>
            <p className="text-lg text-gray-900">Tech Company</p>
          </div>
          <div>
            <h3 className="text-sm font-semibold text-gray-700">Position</h3>
            <p className="text-lg text-gray-900">Software Engineer</p>
          </div>
        </div>

        <button className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition font-semibold">
          Edit Profile
        </button>
      </div>
    </div>
  );
}
